1	/**
2	 * The Loom — session context composition apparatus.
3	 *
4	 * The Loom owns system prompt assembly. Given a role name, it produces
5	 * an AnimaWeave — the composed identity context that The Animator uses
6	 * to launch a session. The work prompt (what the anima should do) is
7	 * not the Loom's concern; it bypasses the Loom and goes directly to
8	 * the Animator.
9	 *
10	 * The Loom resolves the role's permission grants from guild.json, then
11	 * calls the Instrumentarium to resolve the permission-gated tool set.
12	 * Tools are returned on the AnimaWeave so the Animator can pass them
13	 * to the session provider for MCP server configuration.
14	 *
15	 * See: docs/specification.md (loom)
16	 */
17	
18	import type { Plugin, StartupContext, LoadedPlugin } from '@shardworks/nexus-core';
19	import { guild, isLoadedApparatus } from '@shardworks/nexus-core';
20	import type { InstrumentariumApi, ResolvedTool } from '@shardworks/tools-apparatus';
21	import fs from 'node:fs';
22	import path from 'node:path';
23	
24	// ── Public types ──────────────────────────────────────────────────────
25	
26	export interface WeaveRequest {
27	  /**
28	   * The role to weave context for (e.g. 'artificer', 'scribe').
29	   *
30	   * When provided, the Loom resolves role → permissions from guild.json,
31	   * then calls the Instrumentarium to resolve the permission-gated tool set.
32	   * Tools are returned on the AnimaWeave.
33	   *
34	   * When omitted, no tool resolution occurs — the AnimaWeave has no tools.
35	   */
36	  role?: string;
37	}
38	
39	/**
40	 * The output of The Loom's weave() — the composed anima identity context.
41	 *
42	 * Contains the system prompt (produced by the Loom from the anima's
43	 * identity layers) and the resolved tool set for the role. The work
44	 * prompt is not part of the weave — it goes directly to the Animator.
45	 */
46	export interface AnimaWeave {
47	  /**
48	   * The system prompt for the AI process. Composed from guild charter,
49	   * tool instructions, and role instructions. Undefined when no
50	   * composition layers produce content.
51	   */
52	  systemPrompt?: string;
53	  /** The resolved tool set for this role. Undefined when no role is specified or no tools match. */
54	  tools?: ResolvedTool[];
55	  /** Environment variables derived from role identity (e.g. git author/committer). */
56	  environment?: Record<string, string>;
57	}
58	
59	/** The Loom's public API, exposed via `provides`. */
60	export interface LoomApi {
61	  /**
62	   * Weave an anima's session context.
63	   *
64	   * Given a role name, produces an AnimaWeave containing the composed
65	   * system prompt and the resolved tool set. The system prompt is assembled
66	   * from the guild charter, tool instructions (for the resolved tool set),
67	   * and role instructions — in that order.
68	   *
69	   * Tool resolution is active: if a role is provided and the Instrumentarium
70	   * is installed, the Loom resolves role → permissions → tools.
71	   */
72	  weave(request: WeaveRequest): Promise<AnimaWeave>;
73	}
74	
75	// ── Config types ─────────────────────────────────────────────────────
76	
77	/** Role definition in guild.json under the Loom's plugin section. */
78	export interface RoleDefinition {
79	  /** Permission grants in `plugin:level` format. */
80	  permissions: string[];
81	  /**
82	   * When true, permissionless tools are excluded unless the role grants
83	   * `plugin:*` or `*:*` for the tool's plugin. Default: false.
84	   */
85	  strict?: boolean;
86	}
87	
88	/** Loom configuration from guild.json. */
89	export interface LoomConfig {
90	  /** Role definitions keyed by role name. */
91	  roles?: Record<string, RoleDefinition>;
92	}
93	
94	/** Role definition contributed by a kit or apparatus supportKit. */
95	export interface KitRoleDefinition {
96	  /** Permission grants in `plugin:level` format. */
97	  permissions: string[];
98	  /**
99	   * When true, permissionless tools are excluded unless the role grants
100	   * `plugin:*` or `*:*` for the tool's plugin. Default: false.
101	   */
102	  strict?: boolean;
103	  /** Inline role instructions injected into the system prompt. */
104	  instructions?: string;
105	  /**
106	   * Path to an instructions file, relative to the kit's npm package root.
107	   * Resolved at registration time. Mutually exclusive with `instructions`
108	   * (if both are present, `instructions` wins).
109	   */
110	  instructionsFile?: string;
111	}
112	
113	/** Kit contribution interface for role definitions. */
114	export interface LoomKit {
115	  roles?: Record<string, KitRoleDefinition>;
116	}
117	
118	// ── Apparatus factory ─────────────────────────────────────────────────
119	
120	/**
121	 * Create the Loom apparatus plugin.
122	 *
123	 * Returns a Plugin with:
124	 * - `requires: ['tools']` — needs the Instrumentarium for tool resolution
125	 * - `consumes: ['roles']` — declares that the Loom consumes kit role contributions
126	 * - `provides: LoomApi` — the context composition API
127	 */
128	export function createLoom(): Plugin {
129	  let config: LoomConfig = {};
130	  let charterContent: string | undefined;
131	  let roleInstructions: Map<string, string> = new Map();
132	  let kitRoles: Map<string, RoleDefinition> = new Map();
133	
134	  function registerKitRoles(
135	    pluginId: string,
136	    packageName: string,
137	    kit: Record<string, unknown>,
138	    home: string,
139	  ): void {
140	    const rawRoles = kit.roles;
141	    if (typeof rawRoles !== 'object' || rawRoles === null || Array.isArray(rawRoles)) return;
142	
143	    // Compute allowed plugin IDs for dependency-scoped validation
144	    const allowedPlugins = new Set<string>([
145	      pluginId,
146	      ...((kit.requires as string[] | undefined) ?? []),
147	      ...((kit.recommends as string[] | undefined) ?? []),
148	    ]);
149	
150	    for (const [roleName, rawDef] of Object.entries(rawRoles as Record<string, unknown>)) {
151	      // Skip non-object entries silently
152	      if (typeof rawDef !== 'object' || rawDef === null || Array.isArray(rawDef)) continue;
153	
154	      const def = rawDef as Record<string, unknown>;
155	
156	      // Validate permissions field exists and is an array
157	      if (!Array.isArray(def.permissions)) {
158	        console.warn(
159	          `[loom] Kit "${pluginId}" role "${roleName}" is missing required "permissions" array — skipped`,
160	        );
161	        continue;
162	      }
163	
164	      const qualifiedName = `${pluginId}.${roleName}`;
165	
166	      // Guild override check at registration time — skip if guild defines this role
167	      if (config.roles && config.roles[qualifiedName]) continue;
168	
169	      // Dependency-scoped permission filtering
170	      const validPermissions: string[] = [];
171	      for (const perm of def.permissions as string[]) {
172	        if (typeof perm !== 'string') continue;
173	        const colonIdx = perm.indexOf(':');
174	        if (colonIdx === -1) {
175	          console.warn(
176	            `[loom] Kit "${pluginId}" role "${roleName}" permission "${perm}" has no colon separator — dropped`,
177	          );
178	          continue;
179	        }
180	        const permPluginId = perm.slice(0, colonIdx);
181	        if (permPluginId === '*' || !allowedPlugins.has(permPluginId)) {
182	          console.warn(
183	            `[loom] Kit "${pluginId}" role "${roleName}" permission "${perm}" references undeclared plugin "${permPluginId}" — dropped`,
184	          );
185	          continue;
186	        }
187	        validPermissions.push(perm);
188	      }
189	
190	      // Register the role
191	      kitRoles.set(qualifiedName, {
192	        permissions: validPermissions,
193	        ...(def.strict === true ? { strict: true } : {}),
194	      });
195	
196	      // Resolve instructions — inline takes precedence over file
197	      if (typeof def.instructions === 'string' && def.instructions) {
198	        roleInstructions.set(qualifiedName, def.instructions);
199	      } else if (typeof def.instructionsFile === 'string' && def.instructionsFile) {
200	        const filePath = path.join(home, 'node_modules', packageName, def.instructionsFile);
201	        try {
202	          const content = fs.readFileSync(filePath, 'utf-8');
203	          if (content) {
204	            roleInstructions.set(qualifiedName, content);
205	          }
206	        } catch {
207	          console.warn(
208	            `[loom] Could not read instructions file for kit "${pluginId}" role "${roleName}": ${filePath}`,
209	          );
210	        }
211	      }
212	    }
213	  }
214	
215	  const api: LoomApi = {
216	    async weave(request: WeaveRequest): Promise<AnimaWeave> {
217	      const weave: AnimaWeave = {};
218	
219	      // Resolve tools if a role is provided and has a definition.
220	      // Guild-defined roles take precedence over kit-contributed roles.
221	      if (request.role) {
222	        const roleDef = config.roles?.[request.role] ?? kitRoles.get(request.role);
223	        if (roleDef) {
224	          try {
225	            const instrumentarium = guild().apparatus<InstrumentariumApi>('tools');
226	            weave.tools = instrumentarium.resolve({
227	              permissions: roleDef.permissions,
228	              strict: roleDef.strict,
229	              caller: 'anima',
230	            });
231	          } catch {
232	            // Instrumentarium not installed — no tools.
233	            // This shouldn't happen since we require 'tools', but
234	            // fail gracefully rather than crash the session.
235	          }
236	        }
237	      }
238	
239	      // Derive git identity from role name.
240	      if (request.role) {
241	        const displayName = request.role.charAt(0).toUpperCase() + request.role.slice(1);
242	        weave.environment = {
243	          GIT_AUTHOR_NAME: displayName,
244	          GIT_AUTHOR_EMAIL: `${request.role}@nexus.local`,
245	        };
246	      }
247	
248	      // Compose system prompt from available layers: charter → tool instructions → role instructions.
249	      const layers: string[] = [];
250	
251	      if (charterContent) {
252	        layers.push(charterContent);
253	      }
254	
255	      if (weave.tools && weave.tools.length > 0) {
256	        for (const resolvedTool of weave.tools) {
257	          const instructions = resolvedTool.definition.instructions;
258	          if (instructions) {
259	            layers.push(`## Tool: ${resolvedTool.definition.name}\n\n${instructions}`);
260	          }
261	        }
262	      }
263	
264	      if (request.role && roleInstructions.has(request.role)) {
265	        layers.push(roleInstructions.get(request.role)!);
266	      }
267	
268	      if (layers.length > 0) {
269	        weave.systemPrompt = layers.join('\n\n');
270	      }
271	
272	      return weave;
273	    },
274	  };
275	
276	  return {
277	    apparatus: {
278	      requires: ['tools'],
279	      consumes: ['roles'],
280	      provides: api,
281	
282	      start(ctx: StartupContext): void {
283	        const g = guild();
284	        config = g.guildConfig().loom ?? {};
285	        const home = g.home;
286	
287	        // Read charter content at startup and cache it.
288	        charterContent = undefined;
289	        const charterFilePath = path.join(home, 'charter.md');
290	        try {
291	          charterContent = fs.readFileSync(charterFilePath, 'utf-8');
292	        } catch (err: unknown) {
293	          if ((err as NodeJS.ErrnoException).code !== 'ENOENT') throw err;
294	          // No charter.md — check for charter/ directory.
295	          const charterDir = path.join(home, 'charter');
296	          try {
297	            const stat = fs.statSync(charterDir);
298	            if (stat.isDirectory()) {
299	              const mdFiles = fs.readdirSync(charterDir)
300	                .filter(f => f.endsWith('.md'))
301	                .sort();
302	              if (mdFiles.length > 0) {
303	                charterContent = mdFiles
304	                  .map(f => fs.readFileSync(path.join(charterDir, f), 'utf-8'))
305	                  .join('\n\n');
306	              }
307	            }
308	          } catch {
309	            // No charter/ directory either — silently omit.
310	          }
311	        }
312	
313	        // Read role instruction files at startup for all configured (guild) roles.
314	        roleInstructions = new Map();
315	        if (config.roles) {
316	          for (const roleName of Object.keys(config.roles)) {
317	            const rolePath = path.join(home, 'roles', `${roleName}.md`);
318	            try {
319	              const content = fs.readFileSync(rolePath, 'utf-8');
320	              if (content) {
321	                roleInstructions.set(roleName, content);
322	              }
323	            } catch {
324	              // File doesn't exist — silently omit.
325	            }
326	          }
327	        }
328	
329	        // ── Kit role scanning ──────────────────────────────────────────
330	        kitRoles = new Map();
331	
332	        // Phase 1a: Scan all already-loaded standalone kits.
333	        for (const kit of g.kits()) {
334	          registerKitRoles(kit.id, kit.packageName, kit.kit, home);
335	        }
336	
337	        // Phase 1b: Scan already-started apparatus for supportKit roles.
338	        // The Loom requires ['tools'], so apparatus that started before it
339	        // (e.g. Instrumentarium) have already fired plugin:initialized.
340	        for (const app of g.apparatuses()) {
341	          if (app.apparatus.supportKit) {
342	            registerKitRoles(app.id, app.packageName, app.apparatus.supportKit, home);
343	          }
344	        }
345	
346	        // Phase 2: Subscribe to plugin:initialized for apparatus supportKits
347	        // that start after the Loom in the dependency order.
348	        ctx.on('plugin:initialized', (plugin: unknown) => {
349	          const loaded = plugin as LoadedPlugin;
350	          if (isLoadedApparatus(loaded) && loaded.apparatus.supportKit) {
351	            registerKitRoles(loaded.id, loaded.packageName, loaded.apparatus.supportKit, home);
352	          }
353	        });
354	      },
355	    },
356	  };
357	}
