describe('Oculus invalid custom routes', () => {
  it('rejects custom route not starting with /api/', async () => {
    const home = makeTmpDir();
    const port = 18190 + Math.floor(Math.random() * 100);

    const routes: RouteContribution[] = [
      {
        method: 'GET',
