191	export function parseSseLines(buffer: string, handler: (data: string) => void): string {
192	  let idx: number;
193	  while ((idx = buffer.indexOf('\n')) !== -1) {
194	    const line = buffer.slice(0, idx).trim();
195	    buffer = buffer.slice(idx + 1);
196	    if (line.startsWith('data: ')) {
197	      const data = line.slice(6);
198	      if (data === '[DONE]') continue;
199	      handler(data);
200	    }
201	  }
202	  return buffer;
203	}
