241	/**
242	 * Make a streaming API call, yielding chunks and returning the accumulated assistant message.
243	 *
244	 * Parses SSE events, yields SessionChunk objects in real time, and accumulates
245	 * tool call fragments across delta chunks. Returns the fully assembled assistant
246	 * message and final usage info.
247	 */
248	async function* callApiStreaming(
249	  apiEndpoint: string,
250	  token: string,
251	  model: string,
252	  messages: ChatMessage[],
253	  apiTools: ToolDef[],
254	  acc: SessionAccumulator,
255	): AsyncGenerator<SessionChunk, ChatMessage, undefined> {
256	  const response = await fetch(`${apiEndpoint}/chat/completions`, {
257	    method: 'POST',
258	    headers: {
259	      'Content-Type': 'application/json',
260	      'Authorization': `Bearer ${token}`,
261	    },
262	    body: JSON.stringify({
263	      model,
264	      messages,
265	      ...(apiTools.length > 0 ? { tools: apiTools } : {}),
266	      stream: true,
267	      stream_options: { include_usage: true },
268	    }),
269	  });
270	
271	  if (!response.ok) {
272	    const body = await response.text();
273	    throw new Error(`GitHub Models API error: ${response.status} ${body}`);
274	  }
275	
276	  if (!response.body) {
277	    throw new Error('GitHub Models API error: no response body for streaming request');
278	  }
279	
280	  // Accumulate tool call fragments keyed by index
281	  const toolCallFragments = new Map<number, { id: string; name: string; arguments: string }>();
282	  let textContent = '';
283	  let lastId = '';
284	  let buffer = '';
285	
286	  const reader = response.body.getReader();
287	  const decoder = new TextDecoder();
288	
289	  try {
290	    while (true) {
291	      const { done, value } = await reader.read();
292	      if (done) break;
293	
294	      buffer += decoder.decode(value, { stream: true });
295	
296	      // Process complete SSE lines
297	      const chunks: ChatCompletionChunk[] = [];
298	      buffer = parseSseLines(buffer, (data) => {
299	        try {
300	          chunks.push(JSON.parse(data) as ChatCompletionChunk);
301	        } catch {
302	          // Skip malformed JSON
303	        }
304	      });
305	
306	      for (const chunk of chunks) {
307	        if (chunk.id) lastId = chunk.id;
308	
309	        // Accumulate usage from the final chunk (stream_options.include_usage)
310	        if (chunk.usage) {
311	          acc.tokenUsage.inputTokens += chunk.usage.prompt_tokens;
312	          acc.tokenUsage.outputTokens += chunk.usage.completion_tokens;
313	        }
314	
315	        const choice = chunk.choices[0];
316	        if (!choice) continue;
317	
318	        const delta = choice.delta;
319	
320	        // Text content delta
321	        if (delta.content != null && delta.content !== '') {
322	          textContent += delta.content;
323	          process.stderr.write(delta.content);
324	          yield { type: 'text', text: delta.content };
325	        }
326	
327	        // Tool call deltas — accumulate by index
328	        if (delta.tool_calls) {
329	          for (const tc of delta.tool_calls) {
330	            const existing = toolCallFragments.get(tc.index);
331	            if (!existing) {
332	              // First fragment for this tool call — must have id and name
333	              const frag = {
334	                id: tc.id ?? '',
335	                name: tc.function?.name ?? '',
336	                arguments: tc.function?.arguments ?? '',
337	              };
338	              toolCallFragments.set(tc.index, frag);
339	              if (frag.name) {
340	                yield { type: 'tool_use', tool: frag.name };
341	              }
342	            } else {
343	              // Subsequent fragment — accumulate arguments and fill in missing fields
344	              if (tc.id && !existing.id) existing.id = tc.id;
345	              if (tc.function?.name && !existing.name) {
346	                existing.name = tc.function.name;
347	                yield { type: 'tool_use', tool: existing.name };
348	              }
349	              if (tc.function?.arguments) existing.arguments += tc.function.arguments;
350	            }
351	          }
352	        }
353	      }
354	    }
355	  } finally {
356	    reader.releaseLock();
357	  }
358	
359	  if (lastId) acc.providerSessionId = lastId;
360	
361	  // Reconstruct the full assistant message from accumulated deltas
362	  const toolCalls: ToolCall[] = [];
363	  for (const [, frag] of toolCallFragments) {
364	    toolCalls.push({
365	      id: frag.id,
366	      type: 'function',
367	      function: { name: frag.name, arguments: frag.arguments },
368	    });
369	  }
370	
371	  const assistantMsg: ChatMessage = {
372	    role: 'assistant',
373	    content: textContent || null,
374	    ...(toolCalls.length > 0 ? { tool_calls: toolCalls } : {}),
375	  };
376	
377	  return assistantMsg;
378	}
