/* Oculus shared stylesheet — Tokyo Night palette */

/* ── Custom properties ───────────────────────────────────────────── */
:root {
  --bg: #1a1b26;
  --surface: #24283b;
  --surface2: #2f3549;
  --border: #3b4261;
  --text: #c0caf5;
  --text-dim: #565f89;
  --text-bright: #e0e6ff;
  --green: #9ece6a;
  --red: #f7768e;
